import React, { useState } from "react";
import VerifyOTP from "./VerifyOTP";

export default function UserRegister({ closeModal }) {

  const BASE_URL = "http://localhost:8086";

  const [formData, setFormData] = useState({
    username: "",
    name: "",
    email: "",
    password: "",
    confirmPassword: "",
  });

  const [error, setError] = useState("");
  const [goOTP, setGoOTP] = useState(false);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  // ✅ validation
  const validate = () => {
    if (!formData.username || !formData.name || !formData.email) {
      return "All fields are required";
    }

    if (!/^[iI][tT]\d{8}@my\.sliit\.lk$/.test(formData.email)) {
      return "Invalid SLIIT email";
    }

    if (formData.password !== formData.confirmPassword) {
      return "Passwords do not match";
    }

    return "";
  };

  // 📧 send OTP
  const sendOTP = async () => {
    const err = validate();
    if (err) {
      setError(err);
      return;
    }

    try {
      const res = await fetch(`${BASE_URL}/user/send-otp`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email: formData.email }),
      });

      const data = await res.text();

      if (res.ok) {
        localStorage.setItem("registerData", JSON.stringify(formData));
        setGoOTP(true);
      } else {
        setError(data);
      }

    } catch (e) {
      setError("Server error");
    }
  };

  // 🔁 OTP PAGE SWITCH
  if (goOTP) {
    return (
      <div className="relative z-50">
        <VerifyOTP email={formData.email} closeModal={closeModal} />
      </div>
    );
  }

  // 🟦 REGISTER UI
  return (
    <div className="relative z-50 bg-white/10 backdrop-blur-xl p-8 rounded-xl w-96 text-white shadow-lg">

      <h2 className="text-2xl font-bold mb-5">Student Registration</h2>

      <input
        name="username"
        onChange={handleChange}
        placeholder="Username"
        className="w-full p-2 my-2 rounded bg-white/20 text-white placeholder-white/70"
      />

      <input
        name="name"
        onChange={handleChange}
        placeholder="Full Name"
        className="w-full p-2 my-2 rounded bg-white/20 text-white placeholder-white/70"
      />

      <input
        name="email"
        onChange={handleChange}
        placeholder="Email"
        className="w-full p-2 my-2 rounded bg-white/20 text-white placeholder-white/70"
      />

      <input
        type="password"
        name="password"
        onChange={handleChange}
        placeholder="Password"
        className="w-full p-2 my-2 rounded bg-white/20 text-white placeholder-white/70"
      />

      <input
        type="password"
        name="confirmPassword"
        onChange={handleChange}
        placeholder="Confirm Password"
        className="w-full p-2 my-2 rounded bg-white/20 text-white placeholder-white/70"
      />

      {error && (
        <p className="text-red-300 text-sm mt-2">{error}</p>
      )}

      <button
        onClick={sendOTP}
        className="w-full mt-4 bg-sky-500 hover:bg-sky-600 p-2 rounded text-white font-semibold"
      >
        Register (Send OTP)
      </button>

    </div>
  );
}
